run_test() {
    local test_name="$1"
    echo -e "${YELLOW}Testing: $test_name${NC}"
}

pass() {
    echo -e "${GREEN}✓ PASS${NC}"
    ((PASS_COUNT++))
}

fail() {
    local msg="$1"
    echo -e "${RED}✗ FAIL: $msg${NC}"
    ((FAIL_COUNT++))
}

